     1→/**
     2→ * Unit tests for T032: Attribute Influence Stage
     3→ *
     4→ * TDD Approach: These tests MUST FAIL before implementation
     5→ *
     6→ * Tests validate:
     7→ * - All role types (CORE, PRIMARY_BOOST, SECONDARY_BOOST, DISAMBIGUATOR, FILTER)
     8→ * - Bonus calculations and score caps
     9→ * - Role enforcement per SCORING_LOGIC.md
    10→ * - Configuration validation
    11→ */
    12→
    13→import { describe, test, expect, beforeEach } from '@jest/globals';
    14→import { EmailMessage } from '../../src/types/email-message';
    15→import { AttributeContext, AttributeRole } from '../../src/types/attribute-context';
    16→import { CategoryConfiguration } from '../../src/types/category-configuration';
    17→import { executeAttributeInfluence } from '../../src/stages/attribute-influence';
    18→
    19→// Test-specific type for emails with additional properties
    20→type TestEmailMessage = EmailMessage & {
    21→  stage_results?: Record<string, unknown>;
    22→};
    23→
    24→describe('Attribute Influence Stage (T032)', () => {
    25→  let mockEmail: EmailMessage;
    26→  let mockContext: AttributeContext;
    27→  let mockConfig: CategoryConfiguration;
    28→
    29→  beforeEach(() => {
    30→    // Setup test email
    31→    mockEmail = {
    32→      id: 'test-email-123',
    33→      threadId: 'thread-456',
    34→      gmailLabels: ['INBOX'],
    35→      payload: {
    36→        mimeType: 'text/plain',
    37→        headers: [
    38→          { name: 'From', value: 'test@example.com' },
    39→          { name: 'Subject', value: 'Test Email' },
    40→        ],
    41→        body: { data: 'VGVzdCBlbWFpbCBib2R5' },
    42→      },
    43→      bodyPlain: 'Test email body',
    44→      bodyHtml: '<p>Test email body</p>',
    45→      subject: 'Test Email',
    46→      from: {
    47→        email: 'test@example.com',
    48→        raw: 'test@example.com',
    49→      },
    50→      to: [
    51→        {
    52→          email: 'recipient@example.com',
    53→          raw: 'recipient@example.com',
    54→        },
    55→      ],
    56→      date: new Date('2024-01-01T10:00:00Z'),
    57→      snippet: 'Test email body',
    58→      isProcessed: false,
    59→      processingPriority: 1,
    60→    };
    61→
    62→    // Setup attribute context with detected attributes
    63→    mockContext = {
    64→      emailId: 'test-email-123',
    65→      urgency: 'medium',
    66→      domains: ['financial.com'],
    67→      structuralPatterns: ['invoice_pattern'],
    68→      temporalSignals: ['end_of_month'],
    69→      detectionMetadata: {
    70→        financial_domain: {
    71→          detectedAt: new Date(),
    72→          detectionMethod: 'domain_lookup',
    73→          confidence: 0.95,
    74→          evidence: 'financial.com domain',
    75→        },
    76→      },
    77→      influenceApplications: [],
    78→      derivedAttributes: {},
    79→      attributeRelationships: [],
    80→    };
    81→
    82→    // Setup category configuration with attribute relevance matrix
    83→    mockConfig = {
    84→      version: '1.0',
    85→      updated: '2024-01-01',
    86→      top_level_categories: {
    87→        FINANCIAL: {
    88→          subtypes: {
    89→            BILLING: {
    90→              rule_based_classification: {
    91→                high_confidence: [],
    92→                medium_confidence: [],
    93→                low_confidence: [],
    94→              },
    95→            },
    96→          },
    97→        },
    98→        PERSONAL: {
    99→          subtypes: {
   100→            FAMILY: {
   101→              rule_based_classification: {
   102→                high_confidence: [],
   103→                medium_confidence: [],
   104→                low_confidence: [],
   105→              },
   106→            },
   107→          },
   108→        },
   109→      },
   110→      processing_config: {
   111→        category_signals: {},
   112→        settings: {
   113→          disambiguation: {
   114→            confidence_gap_threshold: 0.15,
   115→          },
   116→        },
   117→        confidence_thresholds: {
   118→          high_confidence: 0.8,
   119→          ai_classification_required: 0.4,
   120→          low_confidence: 0.2,
   121→        },
   122→        multi_label_policy: {
   123→          max_labels: 3,
   124→          confidence_threshold: 0.3,
   125→          allowed_combinations: [],
   126→        },
   127→        // Attribute relevance matrix - key for this stage
   128→        attribute_relevance: {
   129→          _roles_legend: {
   130→            CORE: 'Essential attributes that define the category',
   131→            PRIMARY_BOOST: 'Strong positive indicators for the category',
   132→            SECONDARY_BOOST: 'Moderate positive indicators',
   133→            DISAMBIGUATOR: 'Helps choose between similar categories',
   134→            FILTER: 'Rules out inappropriate categories',
   135→            STRUCTURAL: 'Email structure and format indicators',
   136→            DERIVED_LINK: 'Links to derived attribute calculations',
   137→            NEUTRAL: 'No impact on category scoring',
   138→          },
   139→          FINANCIAL: {
   140→            category_roles: {
   141→              financial_domain: 'CORE',
   142→              invoice_pattern: 'PRIMARY_BOOST',
   143→              end_of_month: 'SECONDARY_BOOST',
   144→              urgent_indicator: 'DISAMBIGUATOR',
   145→            },
   146→            subtypes: {
   147→              BILLING: {
   148→                roles: {
   149→                  financial_domain: 'CORE',
   150→                  invoice_pattern: 'CORE',
   151→                  end_of_month: 'PRIMARY_BOOST',
   152→                },
   153→              },
   154→            },
   155→          },
   156→          PERSONAL: {
   157→            category_roles: {
   158→              family_domain: 'CORE',
   159→              personal_greeting: 'PRIMARY_BOOST',
   160→              financial_domain: 'FILTER', // Filters out financial content
   161→            },
   162→            subtypes: {
   163→              FAMILY: {
   164→                roles: {
   165→                  family_domain: 'CORE',
   166→                  personal_greeting: 'CORE',
   167→                },
   168→              },
   169→            },
   170→          },
   171→        },
   172→        // Bonus configuration for different roles
   173→        attribute_bonus_config: {
   174→          role_bonuses: {
   175→            CORE: { bonus: 25, cap: 50 },
   176→            PRIMARY_BOOST: { bonus: 15, cap: 30 },
   177→            SECONDARY_BOOST: { bonus: 8, cap: 16 },
   178→            DISAMBIGUATOR: { bonus: 5, cap: 10 },
   179→            FILTER: { bonus: -20, cap: -40 },
   180→          },
   181→        },
   182→        ai_prompts: {
   183→          feature_extraction: {
   184→            system_prompt: [],
   185→            user_prompt: [],
   186→          },
   187→          final_classification: {
   188→            system_prompt: [],
   189→            user_prompt: [],
   190→          },
   191→        },
   192→      },
   193→    };
   194→  });
   195→
   196→  describe('Core Role Processing', () => {
   197→    test('should apply CORE role bonuses correctly', async () => {
   198→      // This test MUST FAIL before implementation
   199→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   200→
   201→      // CORE attributes should get maximum bonus (25 points)
   202→      expect(result.influence_applications).toContainEqual(
   203→        expect.objectContaining({
   204→          category: 'FINANCIAL',
   205→          attribute: 'financial_domain',
   206→          role: 'CORE',
   207→          bonus_applied: 25,
   208→          score_before: expect.any(Number),
   209→          score_after: expect.any(Number),
   210→        })
   211→      );
   212→    });
   213→
   214→    test('should enforce CORE role caps', async () => {
   215→      // Multiple CORE attributes should be capped at 50 total
   216→      mockContext.detectionMetadata.invoice_pattern = {
   217→        detectedAt: new Date(),
   218→        detectionMethod: 'pattern_match',
   219→        confidence: 0.9,
   220→        evidence: 'Invoice pattern detected',
   221→      };
   222→
   223→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   224→
   225→      const financialCoreInfluences = result.influence_applications.filter(
   226→        (app) => app.category === 'FINANCIAL' && app.role === 'CORE'
   227→      );
   228→
   229→      // Group by subtype (category-level and BILLING subtype should be separate caps)
   230→      const categoryLevelCores = financialCoreInfluences.filter((app) => !app.subtype);
   231→      const billingSubtypeCores = financialCoreInfluences.filter((app) => app.subtype === 'BILLING');
   232→
   233→      const categoryLevelTotal = categoryLevelCores.reduce((sum, app) => sum + app.bonus_applied, 0);
   234→      const billingSubtypeTotal = billingSubtypeCores.reduce((sum, app) => sum + app.bonus_applied, 0);
   235→
   236→      // Each group should be capped at 50
   237→      expect(categoryLevelTotal).toBeLessThanOrEqual(50);
   238→      expect(billingSubtypeTotal).toBeLessThanOrEqual(50);
   239→    });
   240→  });
   241→
   242→  describe('PRIMARY_BOOST Role Processing', () => {
   243→    test('should apply PRIMARY_BOOST bonuses correctly', async () => {
   244→      mockContext.detectionMetadata.invoice_pattern = {
   245→        detectedAt: new Date(),
   246→        detectionMethod: 'pattern_match',
   247→        confidence: 0.8,
   248→        evidence: 'Invoice pattern detected',
   249→      };
   250→
   251→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   252→
   253→      expect(result.influence_applications).toContainEqual(
   254→        expect.objectContaining({
   255→          category: 'FINANCIAL',
   256→          attribute: 'invoice_pattern',
   257→          role: 'PRIMARY_BOOST',
   258→          bonus_applied: 15,
   259→          cap_reached: false,
   260→        })
   261→      );
   262→    });
   263→
   264→    test('should enforce PRIMARY_BOOST caps at 30 points', async () => {
   265→      // Add multiple PRIMARY_BOOST attributes
   266→      mockContext.detectionMetadata.invoice_pattern = {
   267→        detectedAt: new Date(),
   268→        detectionMethod: 'pattern_match',
   269→        confidence: 0.8,
   270→        evidence: 'Invoice pattern detected',
   271→      };
   272→      mockContext.detectionMetadata.billing_keyword = {
   273→        detectedAt: new Date(),
   274→        detectionMethod: 'keyword_match',
   275→        confidence: 0.7,
   276→        evidence: 'Billing keyword found',
   277→      };
   278→
   279→      // Configure additional PRIMARY_BOOST attribute
   280→      mockConfig.processing_config.attribute_relevance.FINANCIAL.category_roles.billing_keyword = 'PRIMARY_BOOST';
   281→
   282→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   283→
   284→      const primaryBoostInfluences = result.influence_applications.filter(
   285→        (app) => app.category === 'FINANCIAL' && app.role === 'PRIMARY_BOOST'
   286→      );
   287→
   288→      const totalPrimaryBonus = primaryBoostInfluences.reduce((sum, app) => sum + app.bonus_applied, 0);
   289→      expect(totalPrimaryBonus).toBeLessThanOrEqual(30);
   290→    });
   291→  });
   292→
   293→  describe('SECONDARY_BOOST Role Processing', () => {
   294→    test('should apply SECONDARY_BOOST bonuses correctly', async () => {
   295→      mockContext.detectionMetadata.end_of_month = {
   296→        detectedAt: new Date(),
   297→        detectionMethod: 'temporal_analysis',
   298→        confidence: 0.6,
   299→        evidence: 'End of month timing',
   300→      };
   301→
   302→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   303→
   304→      expect(result.influence_applications).toContainEqual(
   305→        expect.objectContaining({
   306→          category: 'FINANCIAL',
   307→          attribute: 'end_of_month',
   308→          role: 'SECONDARY_BOOST',
   309→          bonus_applied: 8,
   310→        })
   311→      );
   312→    });
   313→
   314→    test('should enforce SECONDARY_BOOST caps at 16 points', async () => {
   315→      // Add multiple SECONDARY_BOOST attributes
   316→      mockContext.detectionMetadata.end_of_month = {
   317→        detectedAt: new Date(),
   318→        detectionMethod: 'temporal_analysis',
   319→        confidence: 0.6,
   320→        evidence: 'End of month timing',
   321→      };
   322→      mockContext.detectionMetadata.business_hours = {
   323→        detectedAt: new Date(),
   324→        detectionMethod: 'temporal_analysis',
   325→        confidence: 0.5,
   326→        evidence: 'Business hours timing',
   327→      };
   328→
   329→      // Configure additional SECONDARY_BOOST attribute
   330→      mockConfig.processing_config.attribute_relevance.FINANCIAL.category_roles.business_hours = 'SECONDARY_BOOST';
   331→
   332→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   333→
   334→      const secondaryBoostInfluences = result.influence_applications.filter(
   335→        (app) => app.category === 'FINANCIAL' && app.role === 'SECONDARY_BOOST'
   336→      );
   337→
   338→      const totalSecondaryBonus = secondaryBoostInfluences.reduce((sum, app) => sum + app.bonus_applied, 0);
   339→      expect(totalSecondaryBonus).toBeLessThanOrEqual(16);
   340→    });
   341→  });
   342→
   343→  describe('DISAMBIGUATOR Role Processing', () => {
   344→    test('should apply DISAMBIGUATOR bonuses for conflict resolution', async () => {
   345→      mockContext.detectionMetadata.urgent_indicator = {
   346→        detectedAt: new Date(),
   347→        detectionMethod: 'keyword_analysis',
   348→        confidence: 0.7,
   349→        evidence: 'Urgent keywords found',
   350→      };
   351→
   352→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   353→
   354→      expect(result.influence_applications).toContainEqual(
   355→        expect.objectContaining({
   356→          category: 'FINANCIAL',
   357→          attribute: 'urgent_indicator',
   358→          role: 'DISAMBIGUATOR',
   359→          bonus_applied: 5,
   360→        })
   361→      );
   362→    });
   363→
   364→    test('should enforce DISAMBIGUATOR caps at 10 points', async () => {
   365→      // Add multiple DISAMBIGUATOR attributes
   366→      mockContext.detectionMetadata.urgent_indicator = {
   367→        detectedAt: new Date(),
   368→        detectionMethod: 'keyword_analysis',
   369→        confidence: 0.7,
   370→        evidence: 'Urgent keywords found',
   371→      };
   372→      mockContext.detectionMetadata.priority_flag = {
   373→        detectedAt: new Date(),
   374→        detectionMethod: 'header_analysis',
   375→        confidence: 0.6,
   376→        evidence: 'Priority header found',
   377→      };
   378→
   379→      // Configure additional DISAMBIGUATOR attribute
   380→      mockConfig.processing_config.attribute_relevance.FINANCIAL.category_roles.priority_flag = 'DISAMBIGUATOR';
   381→
   382→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   383→
   384→      const disambiguatorInfluences = result.influence_applications.filter(
   385→        (app) => app.category === 'FINANCIAL' && app.role === 'DISAMBIGUATOR'
   386→      );
   387→
   388→      const totalDisambiguatorBonus = disambiguatorInfluences.reduce((sum, app) => sum + app.bonus_applied, 0);
   389→      expect(totalDisambiguatorBonus).toBeLessThanOrEqual(10);
   390→    });
   391→  });
   392→
   393→  describe('FILTER Role Processing', () => {
   394→    test('should apply negative bonuses for FILTER attributes', async () => {
   395→      // PERSONAL category has financial_domain as FILTER
   396→      mockContext.detectionMetadata.financial_domain = {
   397→        detectedAt: new Date(),
   398→        detectionMethod: 'domain_lookup',
   399→        confidence: 0.9,
   400→        evidence: 'Financial domain detected',
   401→      };
   402→
   403→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   404→
   405→      // Should filter out PERSONAL category with negative bonus
   406→      expect(result.influence_applications).toContainEqual(
   407→        expect.objectContaining({
   408→          category: 'PERSONAL',
   409→          attribute: 'financial_domain',
   410→          role: 'FILTER',
   411→          bonus_applied: -20, // Negative bonus
   412→        })
   413→      );
   414→    });
   415→
   416→    test('should enforce FILTER caps at -40 points', async () => {
   417→      // Add multiple FILTER attributes for PERSONAL category
   418→      mockContext.detectionMetadata.financial_domain = {
   419→        detectedAt: new Date(),
   420→        detectionMethod: 'domain_lookup',
   421→        confidence: 0.9,
   422→        evidence: 'Financial domain detected',
   423→      };
   424→      mockContext.detectionMetadata.business_language = {
   425→        detectedAt: new Date(),
   426→        detectionMethod: 'nlp_analysis',
   427→        confidence: 0.8,
   428→        evidence: 'Business language detected',
   429→      };
   430→
   431→      // Configure additional FILTER attribute
   432→      mockConfig.processing_config.attribute_relevance.PERSONAL.category_roles.business_language = 'FILTER';
   433→
   434→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   435→
   436→      const filterInfluences = result.influence_applications.filter(
   437→        (app) => app.category === 'PERSONAL' && app.role === 'FILTER'
   438→      );
   439→
   440→      const totalFilterPenalty = filterInfluences.reduce((sum, app) => sum + app.bonus_applied, 0);
   441→      expect(totalFilterPenalty).toBeGreaterThanOrEqual(-40); // More negative than -40 not allowed
   442→    });
   443→  });
   444→
   445→  describe('Subtype Role Processing', () => {
   446→    test('should apply subtype-specific role bonuses', async () => {
   447→      // BILLING subtype has invoice_pattern as CORE
   448→      mockContext.detectionMetadata.invoice_pattern = {
   449→        detectedAt: new Date(),
   450→        detectionMethod: 'pattern_match',
   451→        confidence: 0.9,
   452→        evidence: 'Invoice pattern detected',
   453→      };
   454→
   455→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   456→
   457→      // Should apply subtype-specific bonus for FINANCIAL.BILLING
   458→      expect(result.influence_applications).toContainEqual(
   459→        expect.objectContaining({
   460→          category: 'FINANCIAL',
   461→          subtype: 'BILLING',
   462→          attribute: 'invoice_pattern',
   463→          role: 'CORE',
   464→          bonus_applied: 25,
   465→        })
   466→      );
   467→    });
   468→
   469→    test('should handle category vs subtype role conflicts', async () => {
   470→      // end_of_month is SECONDARY_BOOST for category but PRIMARY_BOOST for BILLING subtype
   471→      mockContext.detectionMetadata.end_of_month = {
   472→        detectedAt: new Date(),
   473→        detectionMethod: 'temporal_analysis',
   474→        confidence: 0.7,
   475→        evidence: 'End of month timing',
   476→      };
   477→
   478→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   479→
   480→      // Subtype role should take precedence
   481→      const subtypeInfluence = result.influence_applications.find(
   482→        (app) => app.category === 'FINANCIAL' && app.subtype === 'BILLING' && app.attribute === 'end_of_month'
   483→      );
   484→
   485→      expect(subtypeInfluence).toEqual(
   486→        expect.objectContaining({
   487→          role: 'PRIMARY_BOOST', // Subtype role takes precedence
   488→          bonus_applied: 15, // PRIMARY_BOOST bonus
   489→        })
   490→      );
   491→    });
   492→  });
   493→
   494→  describe('Performance and Processing Metadata', () => {
   495→    test('should track processing duration', async () => {
   496→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   497→
   498→      expect(result.processing_duration_ms).toBeGreaterThan(0);
   499→      expect(result.processing_duration_ms).toBeLessThan(1000); // Should be fast
   500→    });
   501→
   502→    test('should track configuration references', async () => {
   503→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   504→
   505→      expect(result.configuration_references).toEqual(
   506→        expect.objectContaining({
   507→          attribute_relevance_path: 'processing_config.attribute_relevance',
   508→          bonus_config_path: 'processing_config.attribute_bonus_config',
   509→        })
   510→      );
   511→    });
   512→
   513→    test('should preserve existing context data', async () => {
   514→      const originalContext = { ...mockContext };
   515→
   516→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   517→
   518→      // Original context should be preserved
   519→      expect(mockContext.emailId).toBe(originalContext.emailId);
   520→      expect(mockContext.detectionMetadata).toEqual(originalContext.detectionMetadata);
   521→      expect(result).toBeDefined();
   522→    });
   523→  });
   524→
   525→  describe('Error Handling and Edge Cases', () => {
   526→    test('should handle missing attribute relevance configuration', async () => {
   527→      // Remove attribute relevance configuration
   528→      delete mockConfig.processing_config.attribute_relevance;
   529→
   530→      await expect(executeAttributeInfluence(mockEmail, mockContext, mockConfig)).rejects.toThrow(
   531→        'Attribute relevance configuration not found'
   532→      );
   533→    });
   534→
   535→    test('should handle unknown attributes gracefully', async () => {
   536→      // Add unknown attribute to context
   537→      mockContext.detectionMetadata.unknown_attribute = {
   538→        detectedAt: new Date(),
   539→        detectionMethod: 'unknown',
   540→        confidence: 0.5,
   541→        evidence: 'Unknown attribute',
   542→      };
   543→
   544→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   545→
   546→      // Should not crash, unknown attributes ignored
   547→      expect(result.influence_applications).not.toContainEqual(
   548→        expect.objectContaining({
   549→          attribute: 'unknown_attribute',
   550→        })
   551→      );
   552→    });
   553→
   554→    test('should handle empty detection metadata', async () => {
   555→      mockContext.detectionMetadata = {};
   556→
   557→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   558→
   559→      expect(result.influence_applications).toHaveLength(0);
   560→      expect(result.processing_duration_ms).toBeGreaterThan(0);
   561→    });
   562→
   563→    test('should validate role configurations', async () => {
   564→      // Invalid role in configuration
   565→      mockConfig.processing_config.attribute_relevance.FINANCIAL.category_roles.financial_domain =
   566→        'INVALID_ROLE' as AttributeRole;
   567→
   568→      await expect(executeAttributeInfluence(mockEmail, mockContext, mockConfig)).rejects.toThrow(
   569→        'Invalid attribute role: INVALID_ROLE'
   570→      );
   571→    });
   572→  });
   573→
   574→  describe('Integration with Previous Stages', () => {
   575→    test('should work with attribute detection results', async () => {
   576→      // Simulate typical attribute detection output
   577→      mockContext.detectionMetadata = {
   578→        financial_domain: {
   579→          detectedAt: new Date(),
   580→          detectionMethod: 'domain_lookup',
   581→          confidence: 0.95,
   582→          evidence: 'Domain: financial.com',
   583→        },
   584→        invoice_pattern: {
   585→          detectedAt: new Date(),
   586→          detectionMethod: 'regex_pattern',
   587→          confidence: 0.88,
   588→          evidence: 'Invoice number pattern found',
   589→        },
   590→        end_of_month: {
   591→          detectedAt: new Date(),
   592→          detectionMethod: 'temporal_analysis',
   593→          confidence: 0.72,
   594→          evidence: 'Email sent on last day of month',
   595→        },
   596→      };
   597→
   598→      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);
   599→
   600→      // Should process all detected attributes with appropriate roles
   601→      // 3 attributes but some attributes apply to both category and subtype levels
   602→      expect(result.influence_applications.length).toBeGreaterThan(0);
   603→
   604→      const financialInfluences = result.influence_applications.filter((app) => app.category === 'FINANCIAL');
   605→      expect(financialInfluences.length).toBeGreaterThan(0); // Should have financial influences
   606→    });
   607→
   608→    test('should preserve stage chain data', async () => {
   609→      // Simulate data from previous stages
   610→      const emailWithStageData = {
   611→        ...mockEmail,
