    47→}
    48→
    49→export interface AttributeDetectorConfig {
    50→  field: string;
    51→  operation: string;
    52→  values: string[];
    53→  weight: number;
    54→  cacheEnabled: boolean;
    55→  parallelSafe: boolean;
    56→}
    57→
    58→/**
    59→ * Attribute influence application per SCORING_LOGIC.md Attribute Relevance Matrix
    60→ */
    61→export interface AttributeInfluenceApplication {
    62→  targetCategory: string;
    63→  attributeUsed: string;
    64→  roleType: AttributeRole;
    65→  scoreImpact: number;
    66→  applicationReason: string;
    67→
    68→  // Parallel processing context
    69→  appliedDuringParallelExecution: boolean;
    70→  dependentOnAttributes: string[];
    71→  influenceTimestamp: Date;
    72→
    73→  // Quality tracking
    74→  influenceReliability: number;
    75→  historicalAccuracy: number;
    76→}
    77→
    78→/**
    79→ * Attribute roles from SCORING_LOGIC.md Attribute Relevance Matrix
    80→ */
    81→export type AttributeRole =
    82→  | 'CORE' // Essential for category identification
    83→  | 'PRIMARY_BOOST' // Strong positive indicator
    84→  | 'SECONDARY_BOOST' // Moderate positive indicator
    85→  | 'DISAMBIGUATOR' // Helps resolve ties between categories
    86→  | 'FILTER' // Can exclude categories
    87→  | 'STRUCTURAL' // Indicates email structure/format
    88→  | 'DERIVED_LINK' // Links to derived attributes
    89→  | 'NEUTRAL'; // No significant influence
    90→
    91→/**
    92→ * Derived attribute calculation results
    93→ */
    94→export interface DerivedAttributeResult {
    95→  attributeName: string;
    96→  derivationLogic: string;
    97→  sourceAttributes: string[];
    98→  calculatedValue: unknown;
    99→  confidence: number;
   100→
   101→  // Parallel processing metadata
   102→  calculatedDuringParallelExecution: boolean;
   103→  calculationTimeMs: number;
   104→  cacheHit: boolean;
   105→
   106→  // Quality metrics
   107→  derivationAccuracy: number;
   108→  logicConsistency: number;
   109→}
   110→
   111→/**
   112→ * Relationships between attributes for cross-attribute analysis
   113→ */
   114→export interface AttributeRelationship {
   115→  fromAttribute: string;
   116→  toAttribute: string;
   117→  relationshipType: 'implies' | 'excludes' | 'enhances' | 'diminishes' | 'neutral';
   118→  strength: number; // 0.0 to 1.0
   119→  reason: string;
   120→
   121→  // Context tracking
   122→  discoveredDuringProcessing: boolean;
   123→  validatedAcrossEmails: number;
   124→  conflictOccurrences: number;
   125→}
