     1→/**
     2→ * T032: Attribute Influence Stage Implementation
     3→ *
     4→ * Applies role-based bonuses and penalties based on the attribute relevance matrix.
     5→ * Implements sophisticated role enforcement per SCORING_LOGIC.md.
     6→ *
     7→ * Reference: AttributeInfluenceNode.js (role-based bonuses, bounded adjustments)
     8→ * Config: processing_config.attribute_relevance (CORE/PRIMARY_BOOST/SECONDARY_BOOST/DISAMBIGUATOR/FILTER roles)
     9→ * Logic: Attribute bonus mapping and role enforcement per SCORING_LOGIC.md
    10→ */
    11→
    12→import { EmailMessage } from '../types/email-message';
    13→import { AttributeContext } from '../types/attribute-context';
    14→import { CategoryConfiguration, AttributeRole } from '../types/category-configuration';
    15→
    16→/**
    17→ * Result of attribute influence stage with role-based bonuses
    18→ */
    19→export interface AttributeInfluenceResult {
    20→  influence_applications: AttributeInfluenceApplication[];
    21→  processing_duration_ms: number;
    22→  configuration_references: {
    23→    attribute_relevance_path: string;
    24→    bonus_config_path: string;
    25→  };
    26→  // Preserve previous stage data
    27→  [key: string]: unknown;
    28→}
    29→
    30→/**
    31→ * Individual attribute influence application
    32→ */
    33→export interface AttributeInfluenceApplication {
    34→  category: string;
    35→  subtype?: string;
    36→  attribute: string;
    37→  role: AttributeRole;
    38→  bonus_applied: number;
    39→  score_before: number;
    40→  score_after: number;
    41→  cap_reached: boolean;
    42→  application_metadata: {
    43→    detection_confidence: number;
    44→    role_source: 'category' | 'subtype';
    45→    cap_type: 'role_cap' | 'no_cap';
    46→  };
    47→}
    48→
    49→/**
    50→ * Role bonus configuration
    51→ */
    52→interface RoleBonusConfig {
    53→  bonus: number;
    54→  cap: number;
    55→}
    56→
    57→/**
    58→ * Execute attribute influence stage
    59→ *
    60→ * Applies role-based bonuses to categories based on detected attributes
    61→ * and the attribute relevance matrix configuration.
    62→ */
    63→export async function executeAttributeInfluence(
    64→  email: EmailMessage,
    65→  context: AttributeContext,
    66→  config: CategoryConfiguration
    67→): Promise<AttributeInfluenceResult> {
    68→  const startTime = Date.now();
    69→
    70→  // Validate configuration
    71→  if (!config.processing_config?.attribute_relevance) {
    72→    throw new Error('Attribute relevance configuration not found');
    73→  }
    74→
    75→  // Validate attribute bonus configuration exists
    76→  if (!config.processing_config?.attributes?.attribute_bonus_map) {
    77→    throw new Error('Attribute bonus configuration not found');
    78→  }
    79→
    80→  const attributeRelevance = config.processing_config.attribute_relevance;
    81→  const roleBonuses = config.processing_config.attributes.attribute_bonus_map;
    82→
    83→  const influenceApplications: AttributeInfluenceApplication[] = [];
    84→
    85→  // Process each detected attribute
    86→  for (const [attributeName, metadata] of Object.entries(context.detectionMetadata)) {
    87→    // Apply influence for each category
    88→    for (const categoryName of Object.keys(config.processing_config.top_level_categories)) {
    89→      const categoryConfig = attributeRelevance[categoryName];
    90→      if (!categoryConfig) continue;
    91→
    92→      // Check category-level roles - handle union type safely
    93→      const categoryRole =
    94→        'category_roles' in categoryConfig ? categoryConfig.category_roles?.[attributeName] : undefined;
    95→      if (categoryRole) {
    96→        validateAttributeRole(categoryRole);
    97→
    98→        const application = applyAttributeInfluence(
    99→          categoryName,
   100→          undefined, // No subtype for category-level
   101→          attributeName,
   102→          categoryRole,
   103→          metadata.confidence,
   104→          { bonus: roleBonuses[categoryName]?.[attributeName] || 0, cap: 1.0 },
   105→          'category'
   106→        );
   107→
   108→        influenceApplications.push(application);
   109→      }
   110→
   111→      // Check subtype-level roles - handle union type safely
   112→      if ('subtypes' in categoryConfig && categoryConfig.subtypes) {
   113→        for (const [subtypeName, subtypeConfig] of Object.entries(categoryConfig.subtypes)) {
   114→          const subtypeRole = subtypeConfig.roles?.[attributeName];
   115→          if (subtypeRole) {
   116→            validateAttributeRole(subtypeRole);
   117→
   118→            const application = applyAttributeInfluence(
   119→              categoryName,
   120→              subtypeName,
   121→              attributeName,
   122→              subtypeRole,
   123→              metadata.confidence,
   124→              { bonus: roleBonuses[categoryName]?.[attributeName] || 0, cap: 1.0 },
   125→              'subtype'
   126→            );
   127→
   128→            influenceApplications.push(application);
   129→          }
   130→        }
   131→      }
   132→    }
   133→  }
   134→
   135→  // Apply role caps by category and role type
   136→  const roleBonusConfigs = extractRoleBonusConfigs(config, attributeRelevance);
   137→  const cappedApplications = applyRoleCaps(influenceApplications, roleBonusConfigs);
   138→
   139→  const processingDuration = Math.max(1, Date.now() - startTime);
   140→
   141→  // Preserve any previous stage data from the email input
   142→  const emailData = email as EmailMessage & Record<string, unknown>;
   143→  const result: AttributeInfluenceResult = {
   144→    influence_applications: cappedApplications,
   145→    processing_duration_ms: processingDuration,
   146→    configuration_references: {
   147→      attribute_relevance_path: 'processing_config.attribute_relevance',
   148→      bonus_config_path: 'processing_config.attribute_bonus_config',
   149→    },
   150→  };
   151→
   152→  // Preserve stage chain data
   153→  if ('candidate_scores' in emailData && emailData.candidate_scores) {
   154→    result.candidate_scores = emailData.candidate_scores;
   155→  }
   156→  if ('stage_results' in emailData && emailData.stage_results) {
   157→    result.stage_results = {
   158→      ...(emailData.stage_results as Record<string, unknown>),
   159→      attribute_influence: { completed: true },
   160→    };
   161→  }
   162→
   163→  return result;
   164→}
   165→
   166→/**
   167→ * Apply attribute influence for a specific category/subtype combination
   168→ */
   169→function applyAttributeInfluence(
   170→  category: string,
   171→  subtype: string | undefined,
   172→  attribute: string,
   173→  role: AttributeRole,
   174→  confidence: number,
   175→  bonusConfig: RoleBonusConfig,
   176→  roleSource: 'category' | 'subtype'
   177→): AttributeInfluenceApplication {
   178→  const baseBonusAmount = bonusConfig.bonus;
   179→
