      // PERSONAL category has financial_domain as FILTER
      mockContext.detectionMetadata.financial_domain = {
        detectedAt: new Date(),
        detectionMethod: 'domain_lookup',
        confidence: 0.9,
        evidence: 'Financial domain detected',
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // Should filter out PERSONAL category with negative bonus
      expect(result.influence_applications).toContainEqual(
        expect.objectContaining({
          category: 'PERSONAL',
          attribute: 'financial_domain',
          role: 'FILTER',
          bonus_applied: -20, // Negative bonus
        })
      );
    });

    test('should enforce FILTER caps at -40 points', async () => {
      // Add multiple FILTER attributes for PERSONAL category
      mockContext.detectionMetadata.financial_domain = {
        detectedAt: new Date(),
        detectionMethod: 'domain_lookup',
        confidence: 0.9,
        evidence: 'Financial domain detected',
      };
      mockContext.detectionMetadata.business_language = {
        detectedAt: new Date(),
        detectionMethod: 'nlp_analysis',
        confidence: 0.8,
        evidence: 'Business language detected',
      };

      // Configure additional FILTER attribute
      mockConfig.processing_config.attribute_relevance.PERSONAL.category_roles.business_language = 'FILTER';

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      const filterInfluences = result.influence_applications.filter(
        (app) => app.category === 'PERSONAL' && app.role === 'FILTER'
      );

      const totalFilterPenalty = filterInfluences.reduce((sum, app) => sum + app.bonus_applied, 0);
      expect(totalFilterPenalty).toBeGreaterThanOrEqual(-40); // More negative than -40 not allowed
    });
  });

  describe('Subtype Role Processing', () => {
    test('should apply subtype-specific role bonuses', async () => {
      // BILLING subtype has invoice_pattern as CORE
      mockContext.detectionMetadata.invoice_pattern = {
        detectedAt: new Date(),
        detectionMethod: 'pattern_match',
        confidence: 0.9,
        evidence: 'Invoice pattern detected',
