/**
 * Unit tests for T032: Attribute Influence Stage
 *
 * TDD Approach: These tests MUST FAIL before implementation
 *
 * Tests validate:
 * - All role types (CORE, PRIMARY_BOOST, SECONDARY_BOOST, DISAMBIGUATOR, FILTER)
 * - Bonus calculations and score caps
 * - Role enforcement per SCORING_LOGIC.md
 * - Configuration validation
 */

import { describe, test, expect, beforeEach } from '@jest/globals';
import { EmailMessage } from '../../src/types/email-message';
import { AttributeContext, AttributeRole } from '../../src/types/attribute-context';
import { CategoryConfiguration } from '../../src/types/category-configuration';
import { executeAttributeInfluence } from '../../src/stages/attribute-influence';

// Test-specific type for emails with additional properties
type TestEmailMessage = EmailMessage & {
  stage_results?: Record<string, unknown>;
};

describe('Attribute Influence Stage (T032)', () => {
  let mockEmail: EmailMessage;
  let mockContext: AttributeContext;
  let mockConfig: CategoryConfiguration;

  beforeEach(() => {
    // Setup test email
    mockEmail = {
      id: 'test-email-123',
      threadId: 'thread-456',
      gmailLabels: ['INBOX'],
      payload: {
        mimeType: 'text/plain',
        headers: [
          { name: 'From', value: 'test@example.com' },
          { name: 'Subject', value: 'Test Email' },
        ],
        body: { data: 'VGVzdCBlbWFpbCBib2R5' },
      },
      bodyPlain: 'Test email body',
      bodyHtml: '<p>Test email body</p>',
      subject: 'Test Email',
      from: {
        email: 'test@example.com',
        raw: 'test@example.com',
      },
      to: [
        {
          email: 'recipient@example.com',
          raw: 'recipient@example.com',
        },
      ],
      date: new Date('2024-01-01T10:00:00Z'),
      snippet: 'Test email body',
      isProcessed: false,
      processingPriority: 1,
    };

    // Setup attribute context with detected attributes
    mockContext = {
      emailId: 'test-email-123',
      urgency: 'medium',
      domains: ['financial.com'],
      structuralPatterns: ['invoice_pattern'],
      temporalSignals: ['end_of_month'],
      detectionMetadata: {
        financial_domain: {
          detectedAt: new Date(),
          detectionMethod: 'domain_lookup',
          confidence: 0.95,
          parallelProcessed: false,
          dependencies: [],
          sourceField: 'from.address',
          matchedValue: 'financial.com',
          detectorConfig: {
            field: 'from.address',
            operation: 'domain_extract',
            values: ['financial.com'],
            weight: 1.0,
            cacheEnabled: true,
            parallelSafe: true,
          },
          detectionTimeMs: 5,
          cacheUsed: false,
          retryCount: 0,
        },
      },
      influenceApplications: [],
      derivedAttributes: {},
      attributeRelationships: [],
    };

    // Setup category configuration with attribute relevance matrix
    mockConfig = {
      version: '1.0',
      lastModified: new Date('2024-01-01'),
      hash: 'test-hash',
