                  medium_confidence: [],
                  low_confidence: [],
                },
              },
            },
            ai_final_classification: {
              category_description: 'Financial content',
              decision_criteria: ['financial keywords'],
            },
          },
          PERSONAL: {
            description: 'Personal emails',
            subtypes: {
              FAMILY: {
                description: 'Family-related emails',
                rule_based_classification: {
                  high_confidence: [],
                  medium_confidence: [],
                  low_confidence: [],
                },
              },
            },
            ai_final_classification: {
              category_description: 'Personal content',
              decision_criteria: ['personal keywords'],
            },
          },
        },
        attributes: {
          schema: {},
