            },
            invoice_pattern: {
              FINANCIAL: 15,
            },
            end_of_month: {
              FINANCIAL: 8,
            },
          },
        },
        // Attribute relevance matrix - key for this stage
        attribute_relevance: {
          _roles_legend: {
            CORE: 'Essential attributes that define the category',
            PRIMARY_BOOST: 'Strong positive indicators for the category',
            SECONDARY_BOOST: 'Moderate positive indicators',
            DISAMBIGUATOR: 'Helps choose between similar categories',
            FILTER: 'Rules out inappropriate categories',
            STRUCTURAL: 'Email structure and format indicators',
            DERIVED_LINK: 'Links to derived attribute calculations',
            NEUTRAL: 'No impact on category scoring',
          },
          FINANCIAL: {
            category_roles: {
              financial_domain: 'CORE',
              invoice_pattern: 'PRIMARY_BOOST',
              end_of_month: 'SECONDARY_BOOST',
              urgent_indicator: 'DISAMBIGUATOR',
            },
            subtypes: {
              BILLING: {
                roles: {
                  financial_domain: 'CORE',
                  invoice_pattern: 'CORE',
                  end_of_month: 'PRIMARY_BOOST',
                },
              },
            },
          },
          PERSONAL: {
            category_roles: {
              family_domain: 'CORE',
              personal_greeting: 'PRIMARY_BOOST',
              financial_domain: 'FILTER', // Filters out financial content
            },
            subtypes: {
              FAMILY: {
                roles: {
                  family_domain: 'CORE',
                  personal_greeting: 'CORE',
                },
              },
            },
          },
        },
        ai_prompts: {
          feature_extraction: {
            system_prompt: ['Extract features'],
