          manual_review_required: 0.2,
          secondary_label_min_gap: 0.1,
        },
        multi_label_policy: {
          max_top_level_labels: 3,
          min_confidence_for_additional: 0.3,
          min_delta_primary_secondary: 0.1,
          allow_financial_actionable_copresence: true,
        },
        domain_signal_overrides: {},
        domain_signal_resolution: {
          mode: 'runtime_resolved',
          source: 'config/domain-sources.json',
          notes: 'Test configuration',
        },
        top_level_categories: {
          FINANCIAL: {
            description: 'Financial emails',
            subtypes: {
              BILLING: {
                description: 'Billing-related emails',
                rule_based_classification: {
                  high_confidence: [],
                  medium_confidence: [],
                  low_confidence: [],
                },
              },
            },
            ai_final_classification: {
              category_description: 'Financial content',
              decision_criteria: ['financial keywords'],
            },
          },
          PERSONAL: {
            description: 'Personal emails',
            subtypes: {
              FAMILY: {
                description: 'Family-related emails',
                rule_based_classification: {
                  high_confidence: [],
                  medium_confidence: [],
                  low_confidence: [],
                },
              },
            },
            ai_final_classification: {
              category_description: 'Personal content',
              decision_criteria: ['personal keywords'],
            },
          },
        },
        attributes: {
          schema: {},
          detectors: [],
          derived: {},
          attribute_bonus_map: {
            financial_domain: {
              FINANCIAL: 25,
              PERSONAL: -20,
            },
            invoice_pattern: {
              FINANCIAL: 15,
            },
            end_of_month: {
              FINANCIAL: 8,
            },
          },
        },
        // Attribute relevance matrix - key for this stage
        attribute_relevance: {
          _roles_legend: {
            CORE: 'Essential attributes that define the category',
            PRIMARY_BOOST: 'Strong positive indicators for the category',
            SECONDARY_BOOST: 'Moderate positive indicators',
            DISAMBIGUATOR: 'Helps choose between similar categories',
            FILTER: 'Rules out inappropriate categories',
            STRUCTURAL: 'Email structure and format indicators',
            DERIVED_LINK: 'Links to derived attribute calculations',
            NEUTRAL: 'No impact on category scoring',
          },
          FINANCIAL: {
            category_roles: {
              financial_domain: 'CORE',
              invoice_pattern: 'PRIMARY_BOOST',
              end_of_month: 'SECONDARY_BOOST',
              urgent_indicator: 'DISAMBIGUATOR',
            },
            subtypes: {
              BILLING: {
                roles: {
                  financial_domain: 'CORE',
                  invoice_pattern: 'CORE',
                  end_of_month: 'PRIMARY_BOOST',
                },
              },
            },
          },
          PERSONAL: {
            category_roles: {
              family_domain: 'CORE',
              personal_greeting: 'PRIMARY_BOOST',
