  describe('Core Role Processing', () => {
    test('should apply CORE role bonuses correctly', async () => {
      // This test MUST FAIL before implementation
      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // CORE attributes should get maximum bonus (25 points)
      expect(result.influence_applications).toContainEqual(
        expect.objectContaining({
          category: 'FINANCIAL',
          attribute: 'financial_domain',
          role: 'CORE',
          bonus_applied: 25,
          score_before: expect.any(Number),
          score_after: expect.any(Number),
        })
      );
    });

    test('should enforce CORE role caps', async () => {
      // Multiple CORE attributes should be capped at 50 total
      mockContext.detectionMetadata.invoice_pattern = {
        detectedAt: new Date(),
        detectionMethod: 'pattern',
        confidence: 0.9,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'body',
        matchedValue: 'invoice',
        detectorConfig: {
          field: 'body',
          operation: 'pattern_match',
          values: ['invoice'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 3,
        cacheUsed: false,
        retryCount: 0,
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      const financialCoreInfluences = result.influence_applications.filter(
        (app) => app.category === 'FINANCIAL' && app.role === 'CORE'
      );

      // Group by subtype (category-level and BILLING subtype should be separate caps)
      const categoryLevelCores = financialCoreInfluences.filter((app) => !app.subtype);
      const billingSubtypeCores = financialCoreInfluences.filter((app) => app.subtype === 'BILLING');

      const categoryLevelTotal = categoryLevelCores.reduce((sum, app) => sum + app.bonus_applied, 0);
      const billingSubtypeTotal = billingSubtypeCores.reduce((sum, app) => sum + app.bonus_applied, 0);

      // Each group should be capped at 50
      expect(categoryLevelTotal).toBeLessThanOrEqual(50);
      expect(billingSubtypeTotal).toBeLessThanOrEqual(50);
    });
  });

  describe('PRIMARY_BOOST Role Processing', () => {
    test('should apply PRIMARY_BOOST bonuses correctly', async () => {
      mockContext.detectionMetadata.invoice_pattern = {
        detectedAt: new Date(),
        detectionMethod: 'pattern',
        confidence: 0.8,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'body',
        matchedValue: 'invoice',
        detectorConfig: {
          field: 'body',
          operation: 'pattern_match',
          values: ['invoice'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 3,
        cacheUsed: false,
        retryCount: 0,
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      expect(result.influence_applications).toContainEqual(
        expect.objectContaining({
          category: 'FINANCIAL',
          attribute: 'invoice_pattern',
          role: 'PRIMARY_BOOST',
