          detectionMethod: 'temporal_analysis',
          confidence: 0.72,
          evidence: 'Email sent on last day of month',
        },
      };

      const result = await executeAttributeInfluence(mockEmail, mockContext, mockConfig);

      // Should process all detected attributes with appropriate roles
      // 3 attributes but some attributes apply to both category and subtype levels
      expect(result.influence_applications.length).toBeGreaterThan(0);

      const financialInfluences = result.influence_applications.filter((app) => app.category === 'FINANCIAL');
      expect(financialInfluences.length).toBeGreaterThan(0); // Should have financial influences
    });

    test('should preserve stage chain data', async () => {
      // Simulate data from previous stages
      const emailWithStageData = {
        ...mockEmail,
        stage_results: {
          hard_assertions: { completed: true },
          strong_indicators: { completed: true },
          rule_scoring: { completed: true },
          attribute_detection: { completed: true },
        },
      } as TestEmailMessage;

      const result = await executeAttributeInfluence(emailWithStageData, mockContext, mockConfig);

      // Should preserve previous stage data
      expect(result.stage_results).toEqual(
        expect.objectContaining({
          hard_assertions: { completed: true },
          strong_indicators: { completed: true },
          rule_scoring: { completed: true },
          attribute_detection: { completed: true },
          attribute_influence: { completed: true },
        })
      );
    });
  });
});

