      mockContext.detectionMetadata.end_of_month = {
        detectedAt: new Date(),
        detectionMethod: 'derived',
        confidence: 0.7,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'date',
        matchedValue: 'end_of_month',
