      mockContext.detectionMetadata.priority_flag = {
        detectedAt: new Date(),
        detectionMethod: 'pattern',
        confidence: 0.6,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'headers',
        matchedValue: 'priority',
        detectorConfig: {
          field: 'headers',
