/**
 * Unit tests for T032: Attribute Influence Stage
 *
 * TDD Approach: These tests MUST FAIL before implementation
 *
 * Tests validate:
 * - All role types (CORE, PRIMARY_BOOST, SECONDARY_BOOST, DISAMBIGUATOR, FILTER)
 * - Bonus calculations and score caps
 * - Role enforcement per SCORING_LOGIC.md
 * - Configuration validation
 */

import { describe, test, expect, beforeEach } from '@jest/globals';
import { EmailMessage } from '../../src/types/email-message';
import { AttributeContext, AttributeRole } from '../../src/types/attribute-context';
import { CategoryConfiguration } from '../../src/types/category-configuration';
import { executeAttributeInfluence } from '../../src/stages/attribute-influence';

// Test-specific type for emails with additional properties
type TestEmailMessage = EmailMessage & {
  stage_results?: Record<string, unknown>;
};

describe('Attribute Influence Stage (T032)', () => {
  let mockEmail: EmailMessage;
  let mockContext: AttributeContext;
  let mockConfig: CategoryConfiguration;

  beforeEach(() => {
    // Setup test email
    mockEmail = {
      id: 'test-email-123',
      threadId: 'thread-456',
      gmailLabels: ['INBOX'],
