          confidence: 0.95,
          parallelProcessed: false,
          dependencies: [],
          sourceField: 'from.address',
          matchedValue: 'financial.com',
          detectorConfig: {
            field: 'from.address',
            operation: 'domain_extract',
            values: ['financial.com'],
            weight: 1.0,
            cacheEnabled: true,
            parallelSafe: true,
          },
          detectionTimeMs: 5,
          cacheUsed: false,
          retryCount: 0,
        },
      },
